def price(n):
    if n is None: return '<span style="color:#ccc;font-size:18px;">—</span>'
    return f'<span style="color:#5A2D91;font-weight:700;font-size:13px;">${n:,.0f}'.replace(",",".") + '</span>'
 
def franq(f):
    if f is None: return '<span style="color:#ccc;">—</span>'
    return f'<span style="background:#EDE8F5;color:#6B3FA0;border-radius:20px;padding:3px 10px;font-size:12px;font-weight:700;font-family:Arial,sans-serif;">{f}</span>'
 
def make_html(name, vehicle, rows, has_tr):
    cols_header = '<th>ASEGURADORA</th><th>TC BÁSICO</th><th>TC FULL</th>'
    if has_tr:
        cols_header += '<th>TODO RIESGO</th><th>FRANQUICIA</th>'
    rows_html = ""
    for r in rows:
        cells = f'<td>{logo_cell(r["logo_key"])}</td><td>{price(r.get("tcb"))}</td><td>{price(r.get("tcf"))}</td>'
        if has_tr:
            cells += f'<td>{price(r.get("tr"))}</td><td>{franq(r.get("fr"))}</td>'
        rows_html += f'<tr>{cells}</tr>'
    return f"""<!DOCTYPE html><html><head><meta charset="UTF-8"><style>{BASE_CSS}</style></head><body>
<div class="card">
<div class="header">
  <div class="header-left"><h2>Hola {name},</h2><p>Elegí Quick, vas a tener beneficios siempre</p></div>
  <img class="logo" src="{QUICK_LOGO_SRC_NEW}" alt="Quick Seguro"/>
</div>
<div class="vehicle">{vehicle}</div>
<table><thead><tr>{cols_header}</tr></thead><tbody>{rows_html}</tbody></table>
{FOOTER_HTML}
</div></body></html>"""
 
def render(html_str, out_path):
    HTML(string=html_str).write_pdf('/tmp/tmp_card.pdf')
    imgs = convert_from_path('/tmp/tmp_card.pdf', dpi=180)
    img = imgs[0]
    arr = np.array(img)
    h, w = arr.shape[:2]
    # Recorte vectorizado del espacio en blanco inferior (rápido, sin bucle Python).
    # Una fila es "contenido" si algún píxel tiene los 3 canales RGB < 240.
    rgb = arr[:, :, :3]
    non_white_rows = np.where(np.any(np.all(rgb < 240, axis=2), axis=1))[0]
    if len(non_white_rows) > 0:
        last = min(int(non_white_rows[-1]) + 25, h)
    else:
        last = h
    img.crop((0, 0, w, last)).save(out_path)
    print(f"✓ {out_path}")
 
 
